query:
-- Verificar usuários
SELECT 'USERS' as tabela, id, name, email, role, ativo FROM users LIMIT 10;

-- Verificar transações
SELECT 'TRANSACTIONS' as tabela, id, adminId, clienteId, tipo, valor, data FROM transactions LIMIT 10;

-- Verificar clientes legados
SELECT 'CLIENTS' as tabela, id, adminId, nome, email FROM clients LIMIT 10;

-- Verificar tabelas vazias
SELECT 'CLIENTES (VAZIA)' as tabela, COUNT(*) as total FROM clientes
UNION ALL
SELECT 'LANCAMENTOS (VAZIA)', COUNT(*) FROM lancamentos
UNION ALL
SELECT 'ESTABELECIMENTOS (VAZIA)', COUNT(*) FROM estabelecimentos;

